/* ── i18n Engine (textContent only — no innerHTML) ── */

// Read lang from URL query string (?lang=fi) only — no localStorage persistence
function _getLangFromURL() {
  try {
    const q = new URLSearchParams(window.location.search).get('lang');
    if (q && I18N[q]) return q;
  } catch(e) {}
  return null;
}

let _lang = _getLangFromURL() || 'en';

function t(key) {
  const val = I18N[_lang] && I18N[_lang][key] !== undefined ? I18N[_lang][key]
            : I18N.en[key] !== undefined ? I18N.en[key] : null;
  return val;
}

function applyI18n() {
  document.querySelectorAll('[data-i18n]').forEach(el => {
    const v = t(el.getAttribute('data-i18n'));
    if (v !== null) el.textContent = v;
  });
  document.querySelectorAll('.lang-btn').forEach(btn => {
    btn.classList.toggle('lang-active', btn.dataset.lang === _lang);
  });
  const langMap = { en:'en', zh:'zh-Hant', fi:'fi', de:'de', ja:'ja' };
  document.documentElement.lang = langMap[_lang] || 'en';
}

function setLanguage(lang) {
  _lang = lang;
  // Update URL so the lang carries over on navigation (no localStorage — refresh resets to EN)
  const params = new URLSearchParams(window.location.search);
  if (lang === 'en') {
    params.delete('lang');
  } else {
    params.set('lang', lang);
  }
  const newSearch = params.toString() ? '?' + params.toString() : '';
  history.replaceState(null, '', window.location.pathname + newSearch + window.location.hash);
  applyI18n();
}

// Carry ?lang=XX across internal page links automatically
document.addEventListener('click', function(e) {
  if (_lang === 'en') return;
  const a = e.target.closest('a[href]');
  if (!a) return;
  const href = a.getAttribute('href');
  if (!href || href.startsWith('http') || href.startsWith('mailto') || href.startsWith('#') || href.startsWith('//')) return;
  e.preventDefault();
  const url = new URL(href, window.location.href);
  url.searchParams.set('lang', _lang);
  window.location.href = url.toString();
});

document.addEventListener('DOMContentLoaded', applyI18n);
